/**
 * @summary List all client users
 */
export const getListClientsUrl = (params?: ListClientsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/backoffice/users/clients?${stringifiedParams}`
    : `/api/backoffice/users/clients`;
};

export const listClients = async (
  params?: ListClientsParams,
  options?: RequestInit,
): Promise<UserListResponse> => {
  return customFetch<UserListResponse>(getListClientsUrl(params), {
    ...options,
    method: "GET",
  });
};

